content.content:
Defaulted container "mongod" out of: mongod, copy-keyfile (init)
{
  config: '/etc/mongod/mongod.conf',
  net: { bindIp: '*' },
  operationProfiling: { mode: 'slowOp', slowOpThresholdMs: 400 },
  replication: { replSet: 'mongodb-replica' },
  security: { authorization: 'enabled', keyFile: '/keyfile/keyfile' },
  storage: {
    dbPath: '/data/db',
    wiredTiger: { engineConfig: { journalCompressor: 'snappy' } }
  },
  systemLog: { verbosity: 2 }
}

